import React, { useState, useRef } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { sendCode, verifyCode, register } from '../services/api';

const STEPS = ['email', 'code', 'password'];

const Register = () => {
  const navigate = useNavigate();
  const [step, setStep] = useState(0);
  const [email, setEmail] = useState('');
  const [code, setCode] = useState(['', '', '', '', '', '']);
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPw, setShowPw] = useState(false);
  const codeRefs = useRef([]);

  const handleSendCode = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      await sendCode(email);
      setSuccess('Verification code sent! Check your inbox.');
      setStep(1);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to send code.');
    } finally {
      setLoading(false);
    }
  };

  const handleCodeChange = (index, value) => {
    if (!/^\d*$/.test(value)) return;
    const newCode = [...code];
    newCode[index] = value.slice(-1);
    setCode(newCode);
    if (value && index < 5) {
      codeRefs.current[index + 1]?.focus();
    }
  };

  const handleCodeKeyDown = (index, e) => {
    if (e.key === 'Backspace' && !code[index] && index > 0) {
      codeRefs.current[index - 1]?.focus();
    }
  };

  const handleCodePaste = (e) => {
    const pasted = e.clipboardData.getData('text').replace(/\D/g, '').slice(0, 6);
    if (pasted.length === 6) {
      setCode(pasted.split(''));
      codeRefs.current[5]?.focus();
    }
  };

  const handleVerifyCode = async (e) => {
    e.preventDefault();
    const fullCode = code.join('');
    if (fullCode.length !== 6) return setError('Please enter the 6-digit code.');
    setError('');
    setLoading(true);
    try {
      await verifyCode(email, fullCode);
      setSuccess('Code verified! Set your password.');
      setStep(2);
    } catch (err) {
      setError(err.response?.data?.message || 'Invalid code.');
    } finally {
      setLoading(false);
    }
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    if (password !== confirmPassword) return setError('Passwords do not match.');
    if (password.length < 8) return setError('Password must be at least 8 characters.');
    setError('');
    setLoading(true);
    try {
      await register({ email, code: code.join(''), password, confirmPassword });
      setSuccess('Account created successfully!');
      setTimeout(() => navigate('/login'), 1500);
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed.');
    } finally {
      setLoading(false);
    }
  };

  const stepConfig = [
    { title: 'Create your account', subtitle: 'Enter your email to get started', icon: '✉️' },
    { title: 'Verify your email', subtitle: `We sent a code to ${email}`, icon: '🔐' },
    { title: 'Set your password', subtitle: 'Choose a strong password', icon: '🔒' },
  ];

  return (
    <div className="auth-bg">
      <div className="auth-card">
        <div className="auth-logo">
          <div className="logo-icon">⚡</div>
          <h1>Hosting Manager</h1>
        </div>

        {/* Step indicator */}
        <div style={{ display: 'flex', gap: '6px', marginBottom: '28px' }}>
          {STEPS.map((_, i) => (
            <div key={i} style={{
              flex: 1, height: '3px', borderRadius: '2px',
              background: i <= step ? 'var(--accent)' : 'var(--border-subtle)',
              transition: 'background 0.3s',
            }} />
          ))}
        </div>

        <h2 className="auth-title">{stepConfig[step].title}</h2>
        <p className="auth-subtitle">{stepConfig[step].subtitle}</p>

        {error && <div className="hm-alert hm-alert-error mb-3">{error}</div>}
        {success && <div className="hm-alert hm-alert-success mb-3">{success}</div>}

        {/* Step 0: Email */}
        {step === 0 && (
          <form onSubmit={handleSendCode}>
            <div className="mb-4">
              <label className="hm-label">Email address</label>
              <input
                type="email"
                className="form-control hm-input"
                placeholder="you@example.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                autoFocus
              />
            </div>
            <button type="submit" className="btn btn-primary-hm w-100" disabled={loading}>
              {loading ? <><span className="hm-spinner me-2"></span>Sending...</> : <>Send verification code <i className="bi bi-arrow-right ms-1"></i></>}
            </button>
          </form>
        )}

        {/* Step 1: Code */}
        {step === 1 && (
          <form onSubmit={handleVerifyCode}>
            <div className="code-input-group" onPaste={handleCodePaste}>
              {code.map((digit, i) => (
                <input
                  key={i}
                  ref={(el) => (codeRefs.current[i] = el)}
                  type="text"
                  inputMode="numeric"
                  maxLength={1}
                  value={digit}
                  onChange={(e) => handleCodeChange(i, e.target.value)}
                  onKeyDown={(e) => handleCodeKeyDown(i, e)}
                  className="form-control code-digit"
                  autoFocus={i === 0}
                />
              ))}
            </div>
            <p style={{ textAlign: 'center', fontSize: '13px', color: 'var(--text-muted)', marginBottom: '20px' }}>
              Didn't receive it?{' '}
              <button
                type="button"
                onClick={handleSendCode}
                style={{ background: 'none', border: 'none', color: 'var(--accent)', cursor: 'pointer', fontWeight: '600', fontSize: '13px', padding: 0 }}
              >
                Resend code
              </button>
            </p>
            <button type="submit" className="btn btn-primary-hm w-100" disabled={loading}>
              {loading ? <><span className="hm-spinner me-2"></span>Verifying...</> : <>Verify code <i className="bi bi-arrow-right ms-1"></i></>}
            </button>
          </form>
        )}

        {/* Step 2: Password */}
        {step === 2 && (
          <form onSubmit={handleRegister}>
            <div className="mb-3">
              <label className="hm-label">Password</label>
              <div className="position-relative">
                <input
                  type={showPw ? 'text' : 'password'}
                  className="form-control hm-input"
                  placeholder="Min. 8 characters"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                  autoFocus
                  style={{ paddingRight: '44px' }}
                />
                <button
                  type="button"
                  onClick={() => setShowPw(!showPw)}
                  style={{ position: 'absolute', right: '12px', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer', fontSize: '16px' }}
                >
                  <i className={`bi bi-eye${showPw ? '-slash' : ''}`}></i>
                </button>
              </div>
              {password && (
                <div style={{ marginTop: '8px' }}>
                  <div style={{ display: 'flex', gap: '4px', marginBottom: '4px' }}>
                    {[1,2,3,4].map(i => (
                      <div key={i} style={{
                        flex: 1, height: '3px', borderRadius: '2px',
                        background: password.length >= i * 3 ? (password.length >= 12 ? 'var(--success)' : password.length >= 8 ? 'var(--warning)' : 'var(--danger)') : 'var(--border-subtle)',
                        transition: 'background 0.3s',
                      }} />
                    ))}
                  </div>
                  <span style={{ fontSize: '11px', color: password.length >= 12 ? 'var(--success)' : password.length >= 8 ? 'var(--warning)' : 'var(--danger)' }}>
                    {password.length >= 12 ? 'Strong' : password.length >= 8 ? 'Good' : 'Too short'}
                  </span>
                </div>
              )}
            </div>
            <div className="mb-4">
              <label className="hm-label">Confirm password</label>
              <input
                type="password"
                className="form-control hm-input"
                placeholder="Repeat your password"
                value={confirmPassword}
                onChange={(e) => setConfirmPassword(e.target.value)}
                required
              />
              {confirmPassword && password !== confirmPassword && (
                <div style={{ fontSize: '12px', color: 'var(--danger)', marginTop: '6px' }}>
                  <i className="bi bi-x-circle me-1"></i>Passwords don't match
                </div>
              )}
              {confirmPassword && password === confirmPassword && (
                <div style={{ fontSize: '12px', color: 'var(--success)', marginTop: '6px' }}>
                  <i className="bi bi-check-circle me-1"></i>Passwords match
                </div>
              )}
            </div>
            <button type="submit" className="btn btn-primary-hm w-100" disabled={loading || password !== confirmPassword}>
              {loading ? <><span className="hm-spinner me-2"></span>Creating account...</> : <>Create account <i className="bi bi-check2 ms-1"></i></>}
            </button>
          </form>
        )}

        <p style={{ textAlign: 'center', marginTop: '24px', fontSize: '14px', color: 'var(--text-muted)' }}>
          Already have an account?{' '}
          <Link to="/login" style={{ color: 'var(--accent)', textDecoration: 'none', fontWeight: '600' }}>
            Sign in
          </Link>
        </p>
      </div>
    </div>
  );
};

export default Register;
